mapper.select:
SELECT id, main_menu, sub_menu, title, content, user_id, user_name, phone, counsel_type, comment_count, visibility_level, is_notice, create_date, modified_date FROM `post` WHERE main_menu = 'withdrawal' AND is_deleted = 0
ORDER BY title ASC ORDER BY title DESC ORDER BY create_date ASC ORDER BY comment_count ASC ORDER BY comment_count DESC ORDER BY create_date DESC
LIMIT #{offset}, #{limit}
